// ── in-memory window.storage stub (artifact-safe fallback) ──────────────
// If the host provides window.storage, we keep it. Otherwise an in-memory
// map stands in so the app renders without throwing. Mirrors the
// get/set(key, shared) signature the app uses.
if (typeof window !== "undefined" && !window.storage) {
  const __mem = new Map();
  const k = (key, shared) => (shared ? "s:" : "p:") + key;
  window.storage = {
    async get(key, shared) {
      const v = __mem.get(k(key, shared));
      return v === undefined ? null : { key, value: v, shared: !!shared };
    },
    async set(key, value, shared) {
      __mem.set(k(key, shared), value);
      return { key, value, shared: !!shared };
    },
    async delete(key, shared) {
      const had = __mem.delete(k(key, shared));
      return { key, deleted: had, shared: !!shared };
    },
    async list(prefix, shared) {
      const pfx = (shared ? "s:" : "p:") + (prefix || "");
      const keys = [...__mem.keys()].filter(x => x.startsWith(pfx)).map(x => x.slice(2));
      return { keys, prefix, shared: !!shared };
    },
  };
}


